#### 1. Structure Validation
```rust
#[test]
fn test_no_separate_tool_articles() {
    let html = export_fixture("claude_session.jsonl");

    // Count article elements
    let assistant_articles = count_pattern(&html, r#"class="message message-assistant""#);
    let tool_articles = count_pattern(&html, r#"class="message message-tool""#);

    // Tool messages should NOT have their own articles
    assert_eq!(tool_articles, 0, "Tool messages should not be separate articles");

    // Should have correct number of message groups
    assert!(assistant_articles > 0);
}

#[test]
fn test_tool_badges_in_header() {
    let html = export_fixture("claude_session.jsonl");

    // Find message-header-right sections
    let headers = extract_pattern(&html, r#"<div class="message-header-right">.*?</div>"#);

    // At least one should contain tool badges
    let has_badges = headers.iter().any(|h| h.contains("tool-badge"));
    assert!(has_badges, "Tool badges should be in message headers");
}

#[test]
fn test_badge_count_matches_tools() {
    // Fixture has 3 tool calls
    let html = export_fixture("claude_session.jsonl");
    let badge_count = count_pattern(&html, r#"class="tool-badge[^"]*""#);
    assert_eq!(badge_count, 3, "Should have 3 tool badges");
}
```

#### 2. CSS Validation
```rust
#[test]
fn test_glassmorphism_css_present() {
    let html = export_fixture("claude_session.jsonl");
    assert!(html.contains("backdrop-filter"), "Glassmorphism requires backdrop-filter");
    assert!(html.contains("blur("), "Should have blur effect");
}

#[test]
fn test_color_variables_defined() {
    let html = export_fixture("claude_session.jsonl");
