    assert!(html.contains("aria-expanded"));
    assert!(html.contains("showPopover") || html.contains("tool-popover"));
}
```

#### 4. Accessibility Validation
```rust
#[test]
fn test_aria_labels_present() {
    let html = export_fixture("claude_session.jsonl");
